IEnumerator EasyWave() {
    for (int i = 0; i < 360; i += 30) {
        if (i % 90 == 0) continue; // Intentional gap for player safety
        float rad = i * Mathf.Deg2Rad;
        Fire(new Vector2(Mathf.Cos(rad), Mathf.Sin(rad)), baseSpeed * 0.5f);
    }
    yield return new WaitForSeconds(2.5f);
}

void Fire(Vector2 dir, float speed) {
    GameObject b = Instantiate(bulletPrefab, transform.position, Quaternion.identity);
    var s = b.GetComponent<Bullet>();
    s.SetDirection(dir);
    s.speed = speed;
}
